 26→/**
 27→ * Counterparty API Client
 28→ *
 29→ * Provides typed methods for Counterparty CRUD operations.
 30→ * All methods return typed data or throw ApiClientError.
 31→ */
 32→export class CounterpartyApiClient {
 33→  private baseUrl: string;
 34→  private fetchFn: typeof globalThis.fetch;
 35→  private defaultHeaders: Record<string, string>;
 36→
 37→  constructor(config: ApiClientConfig = {}) {
 38→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 39→    this.fetchFn = config.fetch ?? fetch;
 40→    this.defaultHeaders = {
 41→      'Content-Type': 'application/json',
 42→      ...config.headers,
 43→    };
 44→  }
 45→
 46→  /**
 47→   * Build full URL for endpoint
 48→   */
 49→  private url(path: string, params?: Record<string, string | undefined>): string {
 50→    const fullUrl = `${this.baseUrl}${path}`;
 51→
 52→    if (params) {
 53→      const searchParams = new URLSearchParams();
 54→      for (const [key, value] of Object.entries(params)) {
 55→        if (value !== undefined) {
 56→          searchParams.append(key, value);
 57→        }
 58→      }
 59→      const queryString = searchParams.toString();
 60→      if (queryString) {
 61→        return `${fullUrl}?${queryString}`;
 62→      }
 63→    }
 64→
 65→    return fullUrl;
 66→  }
 67→
 68→  /**
 69→   * GET /api/counterparties
 70→   *
 71→   * List all counterparties with optional filtering.
 72→   * Supports filtering by type and search.
 73→   *
 74→   * @returns Array of counterparties with count
 75→   */
 76→  async getCounterparties(params?: CounterpartyListParams): Promise<ApiListResponse<CounterpartyData>> {
 77→    const response = await this.fetchFn(
 78→      this.url('/counterparties', {
 79→        type: params?.type,
 80→        search: params?.search,
 81→      }),
 82→      {
 83→        headers: this.defaultHeaders,
 84→      }
 85→    );
 86→
 87→    if (!response.ok) {
 88→      return parseApiError(response);
 89→    }
 90→
 91→    return parseJson<ApiListResponse<CounterpartyData>>(response);
 92→  }
 93→
 94→  /**
 95→   * GET /api/counterparties/[id]
 96→   *
 97→   * Fetch a single counterparty by ID.
 98→   *
 99→   * @param id - Counterparty UUID
100→   * @returns Counterparty data
101→   * @throws ApiClientError with 404 if not found
102→   */
103→  async getCounterparty(id: string): Promise<ApiResponse<CounterpartyData>> {
104→    if (!id) {
105→      throw new ApiClientError(400, 'Validation failed', 'id is required');
106→    }
107→
108→    const response = await this.fetchFn(this.url(`/counterparties/${id}`), {
109→      headers: this.defaultHeaders,
110→    });
111→
112→    if (!response.ok) {
113→      return parseApiError(response);
114→    }
115→
116→    return parseJson<ApiResponse<CounterpartyData>>(response);
117→  }
118→
119→  /**
120→   * POST /api/counterparties
121→   *
122→   * Create a new counterparty.
123→   *
124→   * @param data - Counterparty creation input
125→   * @returns Created counterparty data
126→   * @throws ApiClientError with 400 on validation errors
127→   */
128→  async createCounterparty(data: CounterpartyCreateInput): Promise<ApiResponse<CounterpartyData>> {
129→    const response = await this.fetchFn(this.url('/counterparties'), {
130→      method: 'POST',
131→      headers: this.defaultHeaders,
132→      body: JSON.stringify(data),
133→    });
134→
135→    if (!response.ok) {
136→      return parseApiError(response);
137→    }
138→
139→    return parseJson<ApiResponse<CounterpartyData>>(response);
140→  }
141→
142→  /**
143→   * PUT /api/counterparties/[id]
144→   *
145→   * Update an existing counterparty.
146→   * Only provided fields are updated (partial update).
147→   *
148→   * @param id - Counterparty UUID
149→   * @param data - Counterparty update input (all fields optional)
150→   * @returns Updated counterparty data
151→   * @throws ApiClientError with 404 if counterparty not found
152→   */
153→  async updateCounterparty(
154→    id: string,
155→    data: CounterpartyUpdateInput
156→  ): Promise<ApiResponse<CounterpartyData>> {
157→    if (!id) {
158→      throw new ApiClientError(400, 'Validation failed', 'id is required');
159→    }
160→
161→    const response = await this.fetchFn(this.url(`/counterparties/${id}`), {
162→      method: 'PUT',
163→      headers: this.defaultHeaders,
164→      body: JSON.stringify(data),
165→    });
166→
167→    if (!response.ok) {
168→      return parseApiError(response);
169→    }
170→
171→    return parseJson<ApiResponse<CounterpartyData>>(response);
172→  }
173→
174→  /**
175→   * DELETE /api/counterparties/[id]
176→   *
177→   * Soft-delete a counterparty by setting deletedAt timestamp.
178→   * Counterparty remains in database but is filtered from queries.
179→   *
180→   * @param id - Counterparty UUID
181→   * @returns Deleted counterparty data with success message
182→   * @throws ApiClientError with 404 if counterparty not found
183→   */
184→  async deleteCounterparty(id: string): Promise<ApiResponse<CounterpartyData> & { message: string }> {
185→    if (!id) {
186→      throw new ApiClientError(400, 'Validation failed', 'id is required');
187→    }
188→
189→    const response = await this.fetchFn(this.url(`/counterparties/${id}`), {
190→      method: 'DELETE',
191→      headers: this.defaultHeaders,
192→    });
193→
194→    if (!response.ok) {
195→      return parseApiError(response);
196→    }
197→
198→    return parseJson<ApiResponse<CounterpartyData> & { message: string }>(response);
199→  }
200→}
